@charset "UTF-8";
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap");
/*=========================
  Variables globales / container
=========================*/
:root {
  --font-primary: "Poppins", sans-serif;
  --fw-regular: 400;
  --fw-semibold: 600;
  --color-bg: #65B3EC;
  --color-text-light: #F0F8FF;
  --color-button: #2053A2;
  --color-button-hover: #17407A;
  --radius-main: 12px;
  --radius-pill: 20px;
  --spacing: 1.5rem;
  --spacing-half: 0.75rem;
}

body {
  margin: 0;
  font-family: var(--font-primary);
}

.container {
  width: 100%;
  max-width: 1000px;
  background-color: var(--color-bg);
  border-radius: var(--radius-main);
  padding: var(--spacing);
  margin: 0 auto;
  box-sizing: border-box;
  /* Optionnel : Une petite ombre pour l'intégration propre */
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
}

/*=========================
  Bannière de conseil
=========================*/
.advice-banner {
  height: 100%;
  width: 100%;
  padding: 10px; /* Espace autour du container pour laisser respirer l'ombre */
  box-sizing: border-box;
}

.advice-banner__content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing);
}

.advice-banner__text {
  display: flex;
  flex-direction: column;
  color: #fff;
}

.advice-banner__title {
  font-size: 1.4rem;
  font-weight: var(--fw-semibold);
  display: flex;
  margin: 0 0 4px 0;
  align-items: center;
  gap: 12px;
  line-height: 1.2;
}

.advice-banner__emoji {
  font-size: 1.8rem;
  line-height: 1;
}

.advice-banner__subtitle {
  font-size: 0.95rem;
  font-weight: var(--fw-regular);
  color: var(--color-text-light);
  margin: 0;
}

.advice-banner__actions {
  display: flex;
  flex-direction: column;
  gap: 8px;
  min-width: 220px; /* S'assure que les boutons ont la place */
}

/*=========================
  Boutons (Harmonisés Pilules + Animation)
=========================*/
.btn-advice {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 24px;
  font-family: var(--font-primary);
  font-weight: var(--fw-semibold);
  font-size: 1rem;
  border: none;
  border-radius: var(--radius-pill);
  cursor: pointer;
  transition: all 0.2s ease;
  width: 100%;
  /* Ajout pour l'animation */
  position: relative;
  overflow: hidden;
}

.btn-advice--primary,
.btn-advice--secondary {
  background-color: var(--color-button);
  color: #fff;
}

.btn-advice--primary:hover,
.btn-advice--secondary:hover {
  background-color: var(--color-button-hover);
}

/* Effet de lumière sur les boutons au survol */
.btn-advice::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 50%;
  height: 100%;
  background: linear-gradient(to right, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.3) 50%, rgba(255, 255, 255, 0) 100%);
  transform: skewX(-20deg);
  transition: left 0.6s ease-in-out;
}

.btn-advice:hover::after {
  left: 150%;
}

.btn-advice svg {
  width: 1.25em;
  height: 1.25em;
  flex-shrink: 0;
}

/*=========================
  Mobile ≤768px
=========================*/
@media screen and (max-width: 768px) {
  .advice-banner__content {
    flex-direction: column;
    align-items: center;
    text-align: center;
  }
  .advice-banner__text {
    align-items: center;
    width: 100%;
  }
  .advice-banner__title {
    flex-direction: column;
    gap: 8px;
  }
  .advice-banner__emoji {
    font-size: 2.2rem;
  }
  .advice-banner__actions {
    width: 100%;
    flex-direction: column;
    gap: 12px;
    margin-top: 12px;
    align-items: center;
  }
  .btn-advice {
    width: 100%;
    max-width: 300px;
  }
}

